import React, { useState, useEffect } from 'react';
import { useTable } from 'react-table';

const columns = [
  { Header: 'ID', accessor: 'id' },
  { Header: 'Location', accessor: 'location' }, // Update accessor to 'location'
  { Header: 'Material ID', accessor: 'materialid' },
  { Header: 'Material Name', accessor: 'name' }, // Update accessor to 'materialname'
  { Header: 'Quantity', accessor: 'quantity' },
  { Header: 'Date', accessor: 'date' },
];


function PurchaseFunc() {
  const [purchases, setPurchases] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchPurchases();
  }, []);

  const fetchPurchases = async () => {
    setIsLoading(true);
    setError(null);
  
    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();
  
      const updatedData = data.map(item => ({
        ...item,
        location: item.locationname, // Rename property to 'location'
        materialname: item.name, // Rename property to 'materialname'
      }));
  
      setPurchases(updatedData);
    } catch (error) {
      setError(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    const formData = new FormData(event.target);
    const purchaseData = Object.fromEntries(formData.entries());

    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(purchaseData),
      });

      if (!response.ok) {
        throw new Error('Failed to add purchase');
      }

      // Fetch the updated list of purchases after successful addition
      fetchPurchases();
    } catch (error) {
      console.error(error);
    }
  };

  const tableInstance = useTable({ columns, data: purchases });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  return (
    <div>
      <h1>My Purchases</h1>
      <form onSubmit={handleSubmit}>
        <label htmlFor="location">Location:</label>
        <input type="text" id="location" name="location" required />

        <label htmlFor="materialId">Material ID:</label>
        <input type="text" id="materialid" name="materialid" required />

        <label htmlFor="quantity">Quantity:</label>
        <input type="number" id="quantity" name="quantity" required />

        <button type="submit">Add Purchase</button>
      </form>

      {isLoading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error.message}</div>
      ) : (
        <table {...getTableProps()} style={{ border: '1px solid black' }}>
          <thead>
            {headerGroups.map((headerGroup) => (
              <tr {...headerGroup.getHeaderGroupProps()} style={{ background: 'lightgray' }}>
                {headerGroup.headers.map((column) => (
                  <th
                    {...column.getHeaderProps()}
                    style={{ padding: '5px', border: '1px solid black' }}
                  >
                    {column.render('Header')}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody {...getTableBodyProps()}>
            {rows.map((row) => {
              prepareRow(row);
              return (
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td
                      {...cell.getCellProps()}
                      style={{ padding: '5px', border: '1px solid black' }}
                    >
                      {cell.render('Cell')}
                    </td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default PurchaseFunc;
